     1→import React, { useRef, useState } from "react";
     2→import ReCAPTCHA from "react-google-recaptcha";
     3→import { useNavigate } from "react-router-dom";
     4→
     5→const captchaKey = import.meta.env.VITE_CAPTCHA_KEY;
     6→const captchaSecret = import.meta.env.VITE_CAPTCHA_SECRET;
     7→const serverlUrl = import.meta.env.VITE_SERVER_URL;
     8→
     9→export default function SignInForm({ retrieveDatabase, setLoggedIn }) {
    10→  const [formValue, setFormValue] = useState({ email: "", password: "" });
    11→  const [errorValue, setErrorValue] = useState({});
    12→  const [loading, setLoading] = useState(false);
    13→  const [retrievedUser, setRetrievedUser] = useState(true);
    14→  const [captchaError, setCaptchaError] = useState(false);
    15→  const navigate = useNavigate();
    16→  const captchaRef = useRef();
    17→
    18→  const submitForm = async (e) => {
    19→    e.preventDefault();
    20→    setLoading(true);
    21→    //validate form before sending to server
    22→    setErrorValue(validateForm(formValue));
    23→    //if error object isn't empty stop the process
    24→    if (Object.keys(validateForm(formValue)).length > 0) {
    25→      setLoading(false);
    26→      return null;
    27→    }
    28→    //otherwise check if user registration on the server returns OK and reset the form
    29→    else {
    30→      let captchaToken = captchaRef.current?.getValue();
    31→      if (captchaToken.length === 0) {
    32→        setCaptchaError("ReCaptcha is mandatory");
    33→        setLoading(false);
    34→        return;
    35→      }
    36→      window.scrollTo(0, 0);
    37→      const verify = await verifyCaptcha(captchaToken);
    38→
    39→      if (verify) {
    40→        try {
    41→          const retrievedUserOK = await retrieveDatabase(
    42→            formValue.email.toLowerCase(),
    43→            formValue.password
    44→          );
    45→
    46→          if (retrievedUserOK === false) {
    47→            setRetrievedUser(false);
    48→            setFormValue({ email: "", password: "" });
    49→          } else {
    50→            navigate(`/profile`);
    51→            setLoading(false);
    52→            window.scrollTo(0, 0);
    53→            setRetrievedUser(true);
    54→            setFormValue({ email: "", password: "" });
    55→            setLoggedIn(true);
    56→          }
    57→        } catch (error) {
    58→          console.error("Error during user retrieval:", error);
    59→        } finally {
    60→          setLoading(false);
    61→        }
    62→      } else {
    63→        captchaRef.current?.reset();
    64→        setLoggedIn(false);
    65→        setFormValue({
    66→          firstname: "",
    67→          lastname: "",
    68→          email: "",
    69→          message: "",
    70→        });
    71→        setCaptchaError("");
    72→        setLoading(false);
    73→      }
    74→    }
    75→  };
    76→
    77→  const handleChange = (e) => {
    78→    const { name, value } = e.target;
    79→    setFormValue({ ...formValue, [name]: value });
    80→  };
    81→  const verifyCaptcha = async (captchaToken) => {
    82→    try {
    83→      const response = await fetch(serverlUrl, {
    84→        method: "POST",
    85→        body: JSON.stringify({
    86→          secret: captchaSecret,
    87→          captchaToken,
    88→        }),
    89→        headers: {
    90→          "Content-Type": "application/json",
    91→        },
    92→      });
    93→      if (response.status === 200) {
    94→        return true;
    95→      } else {
    96→        return false;
    97→      }
    98→    } catch (error) {
    99→      console.error("Could not verify captcha!", error.message);
   100→      return false;
   101→    }
   102→  };
   103→  const validateForm = (value) => {
   104→    const errors = {};
   105→    const emailRegex = /^\w+([.-]?\w+)*@\w+([.-]?\w+)*(\.\w{2,3})+$/;
   106→    if (!value.email) {
   107→      errors.email = "Enter your email";
   108→    } else if (!emailRegex.test(value.email)) {
   109→      errors.email = "Invalid email";
   110→    }
   111→    if (!value.password) {
   112→      errors.password = "Password field shouldn't be empty";
   113→    } else if (value.password.length < 8) {
   114→      errors.password = "Password must be min. 8 characters";
   115→    }
   116→    if (!value.email && value.password) {
   117→      errors.email = "Enter your email";
   118→    }
   119→
   120→    return errors;
   121→  };
   122→
   123→  return (
   124→    <React.Fragment>
   125→      {loading ? (
   126→        <div role="status" className="flex flex-col gap-4 items-center">
   127→          <p className="text-indigo-400 text-xl">Almost there...</p>
   128→          <svg
   129→            aria-hidden="true"
   130→            className="w-10 h-10 mt-6 text-gray-200 animate-spin dark:text-gray-600 fill-indigo-400"
   131→            viewBox="0 0 100 101"
   132→            fill="none"
   133→            xmlns="http://www.w3.org/2000/svg">
   134→            <path
   135→              d="M100 50.5908C100 78.2051 77.6142 100.591 50 100.591C22.3858 100.591 0 78.2051 0 50.5908C0 22.9766 22.3858 0.59082 50 0.59082C77.6142 0.59082 100 22.9766 100 50.5908ZM9.08144 50.5908C9.08144 73.1895 27.4013 91.5094 50 91.5094C72.5987 91.5094 90.9186 73.1895 90.9186 50.5908C90.9186 27.9921 72.5987 9.67226 50 9.67226C27.4013 9.67226 9.08144 27.9921 9.08144 50.5908Z"
   136→              fill="currentColor"
   137→            />
   138→            <path
   139→              d="M93.9676 39.0409C96.393 38.4038 97.8624 35.9116 97.0079 33.5539C95.2932 28.8227 92.871 24.3692 89.8167 20.348C85.8452 15.1192 80.8826 10.7238 75.2124 7.41289C69.5422 4.10194 63.2754 1.94025 56.7698 1.05124C51.7666 0.367541 46.6976 0.446843 41.7345 1.27873C39.2613 1.69328 37.813 4.19778 38.4501 6.62326C39.0873 9.04874 41.5694 10.4717 44.0505 10.1071C47.8511 9.54855 51.7191 9.52689 55.5402 10.0491C60.8642 10.7766 65.9928 12.5457 70.6331 15.2552C75.2735 17.9648 79.3347 21.5619 82.5849 25.841C84.9175 28.9121 86.7997 32.2913 88.1811 35.8758C89.083 38.2158 91.5421 39.6781 93.9676 39.0409Z"
   140→              fill="currentFill"
